{
  "title": "सिस्टम प्रॉम्प्ट की भूमिका",
  "group": "मूलभूत सिद्धांत",
  "options": [
    {
      "text": "इसे पहले प्रोसेस किया जाता है और उपयोगकर्ता संदेशों की तुलना में इसका अधिक भार होता है"
    },
    {
      "text": "यह उपयोगकर्ता संदेश के समान है लेकिन अलग तरीके से प्रदर्शित होता है"
    },
    {
      "text": "इसका उपयोग केवल API कॉल के लिए किया जाता है, चैट इंटरफ़ेस के लिए नहीं"
    },
    {
      "text": "यह सत्रों में दीर्घकालिक स्मृति के रूप में बना रहता है"
    }
  ],
  "questionProse": [
    "मैसेज ऐरे में `system` भूमिका बनाम `user` भूमिका का उपयोग करने का व्यावहारिक प्रभाव क्या है?"
  ],
  "explanationProse": [
    "`system` भूमिका को उच्च-प्राथमिकता वाले निर्देशों के रूप में प्रोसेस किया जाता है। मॉडलों को प्रशिक्षित किया जाता है कि वे इसे उपयोगकर्ता संदेशों की तुलना में अधिक भार दें — यह \"डेवलपर ने क्या कहा\" और \"उपयोगकर्ता ने क्या कहा\" के बीच की आर्किटेक्चरल सीमा है।\n\n    यह कोई जादू नहीं है। यह गारंटी नहीं देता कि मॉडल विरोधाभासी उपयोगकर्ता निर्देशों को अनदेखा करेगा (देखें: प्रॉम्प्ट इंजेक्शन)। लेकिन यह मॉडल की आपके निर्देशों का पालन करने की प्रवृत्ति को सार्थक रूप से बढ़ाता है, विशेष रूप से मजबूत निर्देश-पालन वाले मॉडलों पर।\n\n    व्यवहार में: अपने व्यक्तित्व, नियम और व्यवहार संबंधी बाधाओं को `system` में रखें। प्राप्त संदर्भ और उपयोगकर्ता डेटा को `user` में रखें। उपयोगकर्ता-नियंत्रित इनपुट को कभी `system` में न रखें।"
  ]
}
